## ❌ Incorrect

```jsx
const anyAction = (a) => {
  // otherActionの実行条件を逆転させているだけのためNG
  if (!a) {
    return
  }

  otherAction()
}
```

```jsx
const anyAction = (a, b) => {
  // 早期returnの条件内容自体は無関係にチェックするためNG
  if (!a || !b) {
    return
  }

  otherAction()
}
```

```jsx
const anyAction = (a, b) => {
  switch (a) {
    ...
  }

  // 早期returnより前に条件などがあっても、条件が実質逆転しているためNG
  if (!b) {
    return
  }

  otherAction()
}
```

```jsx
const anyAction = (a, b) => {
  if (!a) {
    return
  }
  // 早期returnが分割されているため、前述の早期returnの条件とまとめるべきなのでNG
  if (!b) {
    return
  }

  otherAction()
}
```

```jsx
// 早期returnに分ける必要がないifなのでNG
const anyAction = (a, b) => {
  if (!a) {
    return
  }
  if (b) {
    anyAction()
  }
}
```

